import React, { useEffect, useState } from "react";
import { Pie, Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend
);

function Analytics() {

  const [data, setData] = useState(null);

  useEffect(() => {
    fetch("http://localhost:5000/api/analytics")
      .then(res => res.json())
      .then(result => setData(result));
  }, []);

  if (!data) return <p>Loading...</p>;

  const pieData = {
    labels: ["Placed", "Unplaced"],
    datasets: [
      {
        data: [data.placedStudents, data.unplacedStudents],
        backgroundColor: ["#22c55e", "#ef4444"]
      }
    ]
  };

  const barData = {
    labels: ["Students"],
    datasets: [
      {
        label: "Placed Students",
        data: [data.placedStudents],
        backgroundColor: "#6366f1"
      }
    ]
  };

  return (
    <div className="main">

      <h1>Placement Analytics</h1>

      <div className="cards">

        <div className="card">
          <h3>Total Students</h3>
          <p>{data.totalStudents}</p>
        </div>

        <div className="card">
          <h3>Placed Students</h3>
          <p>{data.placedStudents}</p>
        </div>

        <div className="card">
          <h3>Placement Rate</h3>
          <p>{data.placementRate}%</p>
        </div>

        <div className="card">
          <h3>Average CGPA</h3>
          <p>{data.avgCGPA}</p>
        </div>

      </div>

      <div style={{display:"flex", gap:"40px", marginTop:"40px"}}>

        <div style={{width:"400px"}}>
          <Pie data={pieData}/>
        </div>

        <div style={{width:"400px"}}>
          <Bar data={barData}/>
        </div>

      </div>

    </div>
  );
}

export default Analytics;
